from llama_index.core.workflow import Event, StartEvent, StopEvent, Workflow, step

class WorkflowEvent(Event):
    state: dict

class SelectBranchEvent(WorkflowEvent):
    pass

class RunChecksEvent(WorkflowEvent):
    pass

class BuildArtifactEvent(WorkflowEvent):
    pass

class DeployEvent(WorkflowEvent):
    pass

class VerifyDeploymentEvent(WorkflowEvent):
    pass

class DeployBranchWorkflow(Workflow):
    @step
    async def start(self, ev: StartEvent) -> SelectBranchEvent:
        return SelectBranchEvent(state=dict(ev))

    @step
    async def select_branch(self, ev: SelectBranchEvent) -> RunChecksEvent:
        # If branch is empty, ask the user for the branch name.
        # If branch is main, warn that deployment requires approval.
        # Ask for confirmation before proceeding with main.
        state = dict(ev.state)
        state['last_state'] = 'select_branch'
        return RunChecksEvent(state=state)

    @step
    async def run_checks(self, ev: RunChecksEvent) -> BuildArtifactEvent:
        # Run npm run typecheck and stop with errors on failure.
        # Run npm run test -- --coverage.
        # If coverage is below 80 percent, warn and ask whether to proceed.
        state = dict(ev.state)
        state['last_state'] = 'run_checks'
        return BuildArtifactEvent(state=state)

    @step
    async def build_artifact(self, ev: BuildArtifactEvent) -> DeployEvent:
        # Run npm run build.
        # If build fails, return to Run Checks.
        # Set artifact to dist/{branch}-{timestamp}.tar.gz.
        state = dict(ev.state)
        state['last_state'] = 'build_artifact'
        return DeployEvent(state=state)

    @step
    async def deploy(self, ev: DeployEvent) -> VerifyDeploymentEvent:
        # Deploy artifact to environment.
        # On success, notify Slack and continue to Verify Deployment.
        # On failure, roll back to the previous version, notify the team, and return to Select Branch.
        state = dict(ev.state)
        state['last_state'] = 'deploy'
        return VerifyDeploymentEvent(state=state)

    @step
    async def verify_deployment(self, ev: VerifyDeploymentEvent) -> StopEvent:
        # Run a health check against deploy_url/health.
        # Retry failed health checks up to three times.
        # If health passes, mark the deploy complete.
        # If health still fails after three retries, roll back and return to Select Branch.
        state = dict(ev.state)
        state['last_state'] = 'verify_deployment'
        return StopEvent(result=state)

