from llama_index.core.workflow import Event, StartEvent, StopEvent, Workflow, step

class WorkflowEvent(Event):
    state: dict

class GatherChangesEvent(WorkflowEvent):
    pass

class CategorizeCommitsEvent(WorkflowEvent):
    pass

class GenerateNotesEvent(WorkflowEvent):
    pass

class ReleaseNotesWorkflow(Workflow):
    @step
    async def start(self, ev: StartEvent) -> GatherChangesEvent:
        return GatherChangesEvent(state=dict(ev))

    @step
    async def gather_changes(self, ev: GatherChangesEvent) -> CategorizeCommitsEvent:
        # If git_range is empty, infer it from the last tag to HEAD.
        # Collect commits in git_range using git log.
        # Store commit subjects for categorization.
        state = dict(ev.state)
        state['last_state'] = 'gather_changes'
        return CategorizeCommitsEvent(state=state)

    @step
    async def categorize_commits(self, ev: CategorizeCommitsEvent) -> GenerateNotesEvent:
        # Put commits matching feat: or feature: in features.
        # Put commits matching fix: or bug: in fixes.
        # Put every other commit in chores.
        state = dict(ev.state)
        state['last_state'] = 'categorize_commits'
        return GenerateNotesEvent(state=state)

    @step
    async def generate_notes(self, ev: GenerateNotesEvent) -> StopEvent:
        # Write a Features section only when features is not empty.
        # Write a Bug Fixes section only when fixes is not empty.
        # Write a Maintenance section only when chores is not empty.
        # Write the final markdown to CHANGELOG.md.
        # If the user wants to regenerate, return to Gather Changes.
        state = dict(ev.state)
        state['last_state'] = 'generate_notes'
        return StopEvent(result=state)
